const instances = $input.all();
const results = [];

for (const item of instances) {
  const data = item.json;

  // A API pode retornar array ou objeto único
  const list = Array.isArray(data) ? data : [data];

  for (const inst of list) {
    const name = inst.instance?.instanceName || inst.name || 'Desconhecido';
    const state = inst.instance?.state || inst.connectionStatus || inst.state || 'unknown';
    const phone = inst.instance?.owner || inst.ownerJid || '';
    const profileName = inst.instance?.profileName || inst.profileName || '';

    // Determina se está UP ou DOWN
    const isUp = ['open', 'connected', 'CONNECTED'].includes(state);
    const isConnecting = ['connecting', 'CONNECTING', 'Connecting'].includes(state);

    let status;
    if (isUp) status = 'UP';
    else if (isConnecting) status = 'CONNECTING';
    else status = 'DOWN';

    results.push({
      json: {
        name,
        state,
        status,
        phone: phone.replace('@s.whatsapp.net', ''),
        profileName,
        isUp,
        isConnecting,
        emoji: isUp ? '🟢' : isConnecting ? '🟡' : '🔴'
      }
    });
  }
}

return results;

const items = $input.all();

const up = items.filter(i => i.json.status === 'UP');
const connecting = items.filter(i => i.json.status === 'CONNECTING');
const down = items.filter(i => i.json.status === 'DOWN');

const total = items.length;
const now = new Date().toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' });

// Monta linhas detalhadas por instância
const lines = items.map(i => {
  const d = i.json;
  const phone = d.phone ? ` | 📱 ${d.phone}` : '';
  const profile = d.profileName ? ` (${d.profileName})` : '';
  return `${d.emoji} *${d.name}*${profile}${phone} — \`${d.state}\``;
}).join('\n');

// Resumo de saúde geral
let healthIcon = '✅';
if (down.length > 0 && down.length >= total / 2) healthIcon = '🚨';
else if (down.length > 0 || connecting.length > 0) healthIcon = '⚠️';

const summary = `${healthIcon} *Resumo:* 🟢 ${up.length} UP | 🟡 ${connecting.length} Connecting | 🔴 ${down.length} DOWN`;

const message = [
  `*🤖 Evolution API — Status das Instâncias*`,
  `🕐 ${now}`,
  ``,
  lines,
  ``,
  `━━━━━━━━━━━━━━━━━━━━━`,
  summary,
  `📊 Total: ${total} instâncias monitoradas`
].join('\n');

return [{ json: { message, upCount: up.length, downCount: down.length, connectingCount: connecting.length, total } }];

